package com.helios.platform.controller;import com.helios.platform.model.*;import com.helios.platform.service.DeviceService;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.*;import java.util.*;@RestController@RequestMapping("/api")@CrossOrigin(origins="*") public class DeviceController{private final DeviceService service;public DeviceController(DeviceService service){this.service=service;}@GetMapping("/devices") public Collection<Device> devices(){return service.all();}@GetMapping("/devices/{id}") public ResponseEntity<Device> device(@PathVariable String id){return service.get(id).map(ResponseEntity::ok).orElse(ResponseEntity.notFound().build());}@PostMapping("/devices/{id}/command") public Map<String,Object> command(@PathVariable String id,@RequestBody Map<String,String> body){return Map.of("deviceId",id,"command",body.getOrDefault("command","PING"),"status","ACCEPTED","publishedTo","kafka.commands");}@GetMapping("/telemetry/{id}") public TelemetryEvent telemetry(@PathVariable String id){return service.telemetry(id);}@GetMapping("/events") public List<String> events(){return List.of("DEVICE_REGISTERED","TELEMETRY_RECEIVED","ANOMALY_DETECTED","COMMAND_SENT","ALERT_CREATED");}}
